import{_ as t,c as o,o as r,a4 as d}from"./chunks/framework.I1cCAST3.js";const e="/assets/host_create_p.CuI8A30S.png",u=JSON.parse('{"title":"添加个人主机","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-personal.md","filePath":"docs/hosts/add-personal.md"}'),s={name:"docs/hosts/add-personal.md"},a=d('<h1 id="添加个人主机" tabindex="-1">添加个人主机 <a class="header-anchor" href="#添加个人主机" aria-label="Permalink to &quot;添加个人主机&quot;">​</a></h1><p>将个人服务器添加到 Chaterm，以便您可以直接从工作区通过 SSH 连接。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>添加个人主机之前，请确保您已准备好以下内容：</p><ul><li><strong>Chaterm 已安装</strong> 并在您的机器上运行。如果尚未安装，请参阅 <a href="/docs/start/downloads/">下载</a>。</li><li>目标服务器的 <strong>SSH 凭据</strong> -- 密码或 SSH 私钥。</li><li><strong>服务器 IP 地址</strong>（或主机名）和 SSH 端口号（默认 <code>22</code>）。</li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><p><img src="'+e+'" alt=""></p><ol><li>从左侧边栏打开 <strong>主机管理</strong> 页面。</li><li>点击主机管理页面右上角的 <strong>添加主机</strong> 按钮。</li><li>在打开的 <strong>添加主机</strong> 侧边栏中，将 <strong>设备类型</strong> 设为 <strong>服务器/个人</strong>。</li><li>填写下表所述的其余配置项。</li><li>点击 <strong>创建</strong> 保存主机。</li></ol><h2 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>必填</th></tr></thead><tbody><tr><td><strong>设备类型</strong></td><td>选择 <strong>服务器/个人</strong> 表示这是个人服务器。</td><td>是</td></tr><tr><td><strong>连接 IP 或地址</strong></td><td>目标服务器的 IP 地址或主机名（如 <code>192.168.1.100</code> 或 <code>dev.example.com</code>）。</td><td>是</td></tr><tr><td><strong>端口</strong></td><td>目标服务器上的 SSH 服务端口，默认值为 <code>22</code>。仅在服务器使用非标准端口时才需修改。</td><td>是</td></tr><tr><td><strong>用户名</strong></td><td>SSH 登录用户名（如 <code>root</code>、<code>ubuntu</code>、<code>deploy</code>）。</td><td>是</td></tr><tr><td><strong>认证方式</strong></td><td>选择 <strong>密码</strong> 或 <strong>SSH 密钥</strong>。参见下方提示了解详情。</td><td>是</td></tr><tr><td><strong>SSH 代理</strong></td><td>如果服务器位于防火墙或 NAT 之后，可配置 SSH 代理通过中间服务器路由连接。直接连接时留空。</td><td>否</td></tr><tr><td><strong>别名</strong></td><td>便于识别的显示名称，帮助您在主机列表中快速找到该主机（如 <code>开发 API 服务器</code>）。</td><td>是</td></tr><tr><td><strong>分组</strong></td><td>将主机分配到分组以便于管理（如 <code>development</code>、<code>production</code>）。可选择现有分组或输入新分组名称。</td><td>否</td></tr></tbody></table><h2 id="认证方式说明" tabindex="-1">认证方式说明 <a class="header-anchor" href="#认证方式说明" aria-label="Permalink to &quot;认证方式说明&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">选择认证方式</p><ul><li><strong>密码认证</strong> 是最简单的选项。输入指定用户名的 SSH 密码即可。</li><li><strong>密钥认证</strong> 更安全，推荐用于生产服务器。选择已在 <a href="/docs/manage/keys/">密钥管理</a> 中导入的 SSH 密钥，或点击链接先添加新密钥再返回此处选择。</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>点击 <strong>创建</strong> 后，新主机将出现在主机管理页面的主机列表中。接下来您可以：</p><ul><li><strong>立即连接</strong> -- 点击主机条目打开 SSH 终端会话。详见 <a href="/docs/hosts/connect">连接到主机</a> 了解会话期间可用的终端功能。</li><li><strong>编辑或整理</strong> -- 右键点击主机可重命名、克隆、移动到其他分组或删除。详见 <a href="/docs/hosts/edit-clone-delete">编辑、克隆与删除</a>。</li><li><strong>管理 SSH 密钥</strong> -- 如需后续轮换或添加密钥，请访问 <a href="/docs/manage/keys/">密钥管理</a>。</li></ul>',15),n=[a];function l(c,i,g,h,p,S){return r(),o("div",null,n)}const m=t(s,[["render",l]]);export{u as __pageData,m as default};
